  v_alphabet_len CONSTANT INT := 32;
  v_plaintext TEXT := '';
  v_random_bytes BYTEA;
  v_byte INT;
  v_i INT;
BEGIN
  v_random_bytes := gen_random_bytes(6);
  FOR v_i IN 1..6 LOOP
    v_byte := get_byte(v_random_bytes, v_i - 1);
    v_plaintext := v_plaintext ||
      substr(v_alphabet, 1 + (v_byte % v_alphabet_len), 1);
  END LOOP;
  RETURN v_plaintext;
END;

